import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import LoadingSpinner from '../shared/LoadingSpinner';
import AlertMessage from '../shared/AlertMessage';
import CertificateGenerator from '../CertificateGenerator';

const UserDashboard = ({ activeTabProp }) => {
  const { currentUser } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);
  const certificateId = queryParams.get('certificateId');
  const statusFilter = queryParams.get('status');

  const [certificates, setCertificates] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [statusFilterState, setStatusFilter] = useState(statusFilter);
  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    issued: 0,
    revoked: 0,
  });
  const [activeTab, setActiveTab] = useState(activeTabProp || 'dashboard');
  const [selectedCertificate, setSelectedCertificate] = useState(null);
  const [certificateLoading, setCertificateLoading] = useState(false);
  const [certificateError, setCertificateError] = useState(null);
  const [downloadLoading, setDownloadLoading] = useState(false);
  
  // 当组件初始化或路由参数改变时更新标签页
  useEffect(() => {
    if (activeTabProp) {
      setActiveTab(activeTabProp);
    }
  }, [activeTabProp]);

  // 如果有status过滤参数，更新标签页为certificates
  useEffect(() => {
    if (statusFilter) {
      setActiveTab('certificates');
      setStatusFilter(statusFilter);
    }
  }, [statusFilter]);

  useEffect(() => {
    const fetchUserData = async () => {
      try {
        setLoading(true);
        setError(null);

        const token = localStorage.getItem('token');

        if (!token) {
          throw new Error('Authentication required');
        }

        console.log('Fetching certificates with token:', token.substring(0, 15) + '...');

        // 获取用户的证书
        const response = await fetch('/api/certificates/user', {
          headers: {
            Authorization: `Bearer ${token}`,
          },
          credentials: 'include',
        });

        console.log('Response status:', response.status);

        // 尝试解析响应
        let data;
        try {
          const text = await response.text();
          console.log('Raw response:', text);
          data = text ? JSON.parse(text) : {};
        } catch (parseError) {
          console.error('Error parsing response:', parseError);
          throw new Error('Error parsing server response');
        }

        console.log('Response data:', data);

        if (!response.ok) {
          throw new Error(data.message || 'Failed to fetch certificates');
        }

        // 检查数据格式是否正确
        if (!data.data || !Array.isArray(data.data)) {
          console.warn('Unexpected data format:', data);
          // 设置为空数组，而不是中断
          setCertificates([]);
          setStats({
            total: 0,
            pending: 0,
            issued: 0,
            revoked: 0,
          });
          return;
        }

        // 更新证书列表
        setCertificates(data.data);

        // 计算统计数据
        const calculatedStats = {
          total: data.data.length,
          pending: data.data.filter(cert => cert.status === 'pending').length,
          issued: data.data.filter(cert => cert.status === 'issued').length,
          revoked: data.data.filter(cert => cert.status === 'revoked').length,
        };

        setStats(calculatedStats);
      } catch (err) {
        console.error('Error fetching user data:', err);
        setError(err.message || 'Server error');
      } finally {
        setLoading(false);
      }
    };

    fetchUserData();
  }, []);

  useEffect(() => {
    if (certificateId) {
      fetchCertificateDetails(certificateId);
      setActiveTab('certificate-details');
    }
  }, [certificateId]);

  const fetchCertificateDetails = async (id) => {
    try {
      setCertificateLoading(true);
      setCertificateError(null);

      const token = localStorage.getItem('token');

      if (!token) {
        throw new Error('Authentication required');
      }

      console.log(`开始获取证书ID: ${id}的详情`);
      const response = await fetch(`/api/certificates/${id}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      console.log(`接收到状态码: ${response.status}`);
      
      // 尝试解析响应文本并记录日志
      const responseText = await response.text();
      console.log('接收到原始响应:', responseText);
      
      if (!response.ok) {
        throw new Error(`获取证书失败: ${responseText}`);
      }

      // 解析JSON数据
      const data = responseText ? JSON.parse(responseText) : {};
      console.log('解析后的证书数据:', data);
      
      setSelectedCertificate(data.data);
    } catch (err) {
      console.error('Error fetching certificate details:', err);
      setCertificateError(err.message || 'Failed to load certificate');
    } finally {
      setCertificateLoading(false);
    }
  };

  const handleDownloadCertificate = async (id) => {
    try {
      setDownloadLoading(true);
      const token = localStorage.getItem('token');

      if (!token) {
        throw new Error('需要身份验证');
      }

      console.log(`开始下载证书ID: ${id}`);
      
      // 先获取证书信息以便获取证书编号
      const response = await fetch(`/api/certificates/${id}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      
      if (!response.ok) {
        throw new Error(`获取证书信息失败: ${response.status}`);
      }
      
      const data = await response.json();
      const certificate = data.data;
      
      if (!certificate || !certificate.certificateNumber) {
        throw new Error('证书信息无效或不包含证书编号');
      }
      
      console.log(`获取到证书编号: ${certificate.certificateNumber}`);
      
      // 直接使用证书编号构建下载链接
      const certificateFileName = `${certificate.certificateNumber}.pdf`;
      const downloadUrl = `/certificates/${certificateFileName}`;
      
      console.log(`直接下载链接: ${downloadUrl}`);
      
      // 创建临时链接并点击下载
      const a = document.createElement('a');
      a.href = downloadUrl;
      a.download = `证书-${certificate.certificateNumber}.pdf`;
      a.target = '_blank';
      document.body.appendChild(a);
      a.click();
      
      // 清理
      setTimeout(() => {
        document.body.removeChild(a);
      }, 100);
      
      console.log('下载请求已发送');
    } catch (err) {
      console.error('证书下载错误:', err);
      alert(`下载证书失败: ${err.message}`);
    } finally {
      setTimeout(() => {
        setDownloadLoading(false);
      }, 1000);
    }
  };

  const formatDate = dateString => {
    const options = { year: 'numeric', month: 'long', day: 'numeric' };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  const getStatusBadgeClass = status => {
    switch (status) {
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'issued':
        return 'bg-green-100 text-green-800';
      case 'revoked':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <>
      <div className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        {/* 页面标题 */}
        <div className="md:flex md:items-center md:justify-between mb-4 px-4 sm:px-0">
          <div className="flex-1 min-w-0">
            <h2 className="text-2xl font-bold leading-7 text-gray-900 sm:text-3xl sm:truncate">
              Dashboard
            </h2>
          </div>
        </div>

        {/* 欢迎信息 */}
        <div className="px-4 sm:px-0">
          <h3 className="text-lg font-medium leading-6 text-gray-900">
            Welcome back, {currentUser?.name}!
          </h3>
          <p className="mt-1 text-sm text-gray-600">
            Here&apos;s an overview of your certificates and recent activity.
          </p>
        </div>

        {/* Tab navigation */}
        <div className="border-b border-gray-200 mt-6">
          <nav className="-mb-px flex space-x-8 px-4 sm:px-0">
            <button
              className={`${
                activeTab === 'dashboard'
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm`}
              onClick={() => setActiveTab('dashboard')}
            >
              Dashboard
            </button>
            <button
              className={`${
                activeTab === 'generate-certificate'
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm`}
              onClick={() => setActiveTab('generate-certificate')}
            >
              Generate SIU Certificate
            </button>
            {activeTab === 'certificate-details' && (
              <button
                className="border-blue-500 text-blue-600 whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm"
              >
                Certificate Details
              </button>
            )}
          </nav>
        </div>

        {loading && activeTab === 'dashboard' ? (
          <LoadingSpinner message="Loading your dashboard..." />
        ) : error && activeTab === 'dashboard' ? (
          <AlertMessage
            type="error"
            message={{
              title: 'Failed to load dashboard',
              details: error,
            }}
          />
        ) : (
          <>
            {activeTab === 'dashboard' && (
              <>
                {/* 统计卡片 */}
                <div className="mt-6 grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-4 px-4 sm:px-0">
                  {/* 总证书数量 */}
                  <div className="bg-white overflow-hidden shadow rounded-lg">
                    <div className="px-4 py-5 sm:p-6">
                      <div className="flex items-center">
                        <div className="flex-shrink-0 bg-blue-500 rounded-md p-3">
                          <svg
                            className="h-6 w-6 text-white"
                            xmlns="http://www.w3.org/2000/svg"
                            fill="none"
                            viewBox="0 0 24 24"
                            stroke="currentColor"
                          >
                            <path
                              strokeLinecap="round"
                              strokeLinejoin="round"
                              strokeWidth={2}
                              d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"
                            />
                          </svg>
                        </div>
                        <div className="ml-5 w-0 flex-1">
                          <dl>
                            <dt className="text-sm font-medium text-gray-500 truncate">
                              Total Certificates
                            </dt>
                            <dd>
                              <div className="text-lg font-medium text-gray-900">{stats.total}</div>
                            </dd>
                          </dl>
                        </div>
                      </div>
                    </div>
                    <div className="bg-gray-50 px-4 py-4 sm:px-6">
                      <div className="text-sm">
                        <Link
                          to="/user-certificates"
                          className="font-medium text-blue-600 hover:text-blue-500"
                        >
                          View all<span className="sr-only"> certificates</span>
                        </Link>
                      </div>
                    </div>
                  </div>

                  {/* 待审核证书 */}
                  <div className="bg-white overflow-hidden shadow rounded-lg">
                    <div className="px-4 py-5 sm:p-6">
                      <div className="flex items-center">
                        <div className="flex-shrink-0 bg-yellow-500 rounded-md p-3">
                          <svg
                            className="h-6 w-6 text-white"
                            xmlns="http://www.w3.org/2000/svg"
                            fill="none"
                            viewBox="0 0 24 24"
                            stroke="currentColor"
                          >
                            <path
                              strokeLinecap="round"
                              strokeLinejoin="round"
                              strokeWidth={2}
                              d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"
                            />
                          </svg>
                        </div>
                        <div className="ml-5 w-0 flex-1">
                          <dl>
                            <dt className="text-sm font-medium text-gray-500 truncate">
                              Pending Approval
                            </dt>
                            <dd>
                              <div className="text-lg font-medium text-gray-900">
                                {stats.pending}
                              </div>
                            </dd>
                          </dl>
                        </div>
                      </div>
                    </div>
                    <div className="bg-gray-50 px-4 py-4 sm:px-6">
                      <div className="text-sm">
                        <Link
                          to="/user-certificates?status=pending"
                          className="font-medium text-yellow-600 hover:text-yellow-500"
                        >
                          View pending<span className="sr-only"> certificates</span>
                        </Link>
                      </div>
                    </div>
                  </div>

                  {/* 已颁发证书 */}
                  <div className="bg-white overflow-hidden shadow rounded-lg">
                    <div className="px-4 py-5 sm:p-6">
                      <div className="flex items-center">
                        <div className="flex-shrink-0 bg-green-500 rounded-md p-3">
                          <svg
                            className="h-6 w-6 text-white"
                            xmlns="http://www.w3.org/2000/svg"
                            fill="none"
                            viewBox="0 0 24 24"
                            stroke="currentColor"
                          >
                            <path
                              strokeLinecap="round"
                              strokeLinejoin="round"
                              strokeWidth={2}
                              d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"
                            />
                          </svg>
                        </div>
                        <div className="ml-5 w-0 flex-1">
                          <dl>
                            <dt className="text-sm font-medium text-gray-500 truncate">
                              Issued Certificates
                            </dt>
                            <dd>
                              <div className="text-lg font-medium text-gray-900">
                                {stats.issued}
                              </div>
                            </dd>
                          </dl>
                        </div>
                      </div>
                    </div>
                    <div className="bg-gray-50 px-4 py-4 sm:px-6">
                      <div className="text-sm">
                        <Link
                          to="/user-certificates?status=issued"
                          className="font-medium text-green-600 hover:text-green-500"
                        >
                          View issued<span className="sr-only"> certificates</span>
                        </Link>
                      </div>
                    </div>
                  </div>

                  {/* 已撤销证书 */}
                  <div className="bg-white overflow-hidden shadow rounded-lg">
                    <div className="px-4 py-5 sm:p-6">
                      <div className="flex items-center">
                        <div className="flex-shrink-0 bg-red-500 rounded-md p-3">
                          <svg
                            className="h-6 w-6 text-white"
                            xmlns="http://www.w3.org/2000/svg"
                            fill="none"
                            viewBox="0 0 24 24"
                            stroke="currentColor"
                          >
                            <path
                              strokeLinecap="round"
                              strokeLinejoin="round"
                              strokeWidth={2}
                              d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z"
                            />
                          </svg>
                        </div>
                        <div className="ml-5 w-0 flex-1">
                          <dl>
                            <dt className="text-sm font-medium text-gray-500 truncate">
                              Revoked Certificates
                            </dt>
                            <dd>
                              <div className="text-lg font-medium text-gray-900">
                                {stats.revoked}
                              </div>
                            </dd>
                          </dl>
                        </div>
                      </div>
                    </div>
                    <div className="bg-gray-50 px-4 py-4 sm:px-6">
                      <div className="text-sm">
                        <Link
                          to="/user-certificates?status=revoked"
                          className="font-medium text-red-600 hover:text-red-500"
                        >
                          View revoked<span className="sr-only"> certificates</span>
                        </Link>
                      </div>
                    </div>
                  </div>
                </div>

                {/* 快速操作 */}
                <div className="mt-8 px-4 sm:px-0">
                  <h3 className="text-lg leading-6 font-medium text-gray-900">Quick Actions</h3>
                  <div className="mt-2 grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-3">
                    <div className="bg-white overflow-hidden shadow rounded-lg">
                      <div className="px-4 py-5 sm:p-6">
                        <h3 className="text-lg font-medium text-gray-900">Request Certificate</h3>
                        <p className="mt-1 text-sm text-gray-500">
                          Apply for a new certificate or qualification.
                        </p>
                        <div className="mt-3">
                          <button
                            type="button"
                            onClick={() => setActiveTab('generate-certificate')}
                            className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                          >
                            Apply Now
                          </button>
                        </div>
                      </div>
                    </div>

                    <div className="bg-white overflow-hidden shadow rounded-lg">
                      <div className="px-4 py-5 sm:p-6">
                        <h3 className="text-lg font-medium text-gray-900">Update Profile</h3>
                        <p className="mt-1 text-sm text-gray-500">
                          Update your personal information and security settings.
                        </p>
                        <div className="mt-3">
                          <button
                            type="button"
                            onClick={() => navigate('/profile')}
                            className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500"
                          >
                            View Profile
                          </button>
                        </div>
                      </div>
                    </div>

                    <div className="bg-white overflow-hidden shadow rounded-lg">
                      <div className="px-4 py-5 sm:p-6">
                        <h3 className="text-lg font-medium text-gray-900">Browse Certificates</h3>
                        <p className="mt-1 text-sm text-gray-500">
                          View and manage all your certificates.
                        </p>
                        <div className="mt-3">
                          <button
                            type="button"
                            onClick={() => setActiveTab('certificates')}
                            className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-purple-600 hover:bg-purple-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-purple-500"
                          >
                            View All
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>

                {/* 最近的证书 */}
                <div className="mt-8 px-4 sm:px-0">
                  <div className="sm:flex sm:items-center">
                    <div className="sm:flex-auto">
                      <h3 className="text-lg leading-6 font-medium text-gray-900">
                        Recent Certificates
                      </h3>
                      <p className="mt-1 text-sm text-gray-500">
                        Your most recently requested or updated certificates.
                      </p>
                    </div>
                    <div className="mt-4 sm:mt-0 sm:ml-16 sm:flex-none">
                      <button
                        type="button"
                        onClick={() => setActiveTab('certificates')}
                        className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                      >
                        View All
                      </button>
                    </div>
                  </div>

                  <div className="mt-4 flex flex-col">
                    <div className="-my-2 -mx-4 overflow-x-auto sm:-mx-6 lg:-mx-8">
                      <div className="inline-block min-w-full py-2 align-middle md:px-6 lg:px-8">
                        <div className="overflow-hidden shadow ring-1 ring-black ring-opacity-5 md:rounded-lg">
                          {certificates.length === 0 ? (
                            <div className="bg-white py-12 text-center">
                              <svg
                                className="mx-auto h-12 w-12 text-gray-400"
                                fill="none"
                                viewBox="0 0 24 24"
                                stroke="currentColor"
                                aria-hidden="true"
                              >
                                <path
                                  strokeLinecap="round"
                                  strokeLinejoin="round"
                                  strokeWidth={1}
                                  d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"
                                />
                              </svg>
                              <h3 className="mt-2 text-sm font-medium text-gray-900">
                                No certificates found
                              </h3>
                              <p className="mt-1 text-sm text-gray-500">
                                Get started by requesting your first certificate.
                              </p>
                              <div className="mt-6">
                                <button
                                  type="button"
                                  onClick={() => setActiveTab('generate-certificate')}
                                  className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                                >
                                  Request Certificate
                                </button>
                              </div>
                            </div>
                          ) : (
                            <table className="min-w-full divide-y divide-gray-300">
                              <thead className="bg-gray-50">
                                <tr>
                                  <th
                                    scope="col"
                                    className="py-3.5 pl-4 pr-3 text-left text-sm font-semibold text-gray-900 sm:pl-6"
                                  >
                                    Title
                                  </th>
                                  <th
                                    scope="col"
                                    className="px-3 py-3.5 text-left text-sm font-semibold text-gray-900"
                                  >
                                    Status
                                  </th>
                                  <th
                                    scope="col"
                                    className="px-3 py-3.5 text-left text-sm font-semibold text-gray-900"
                                  >
                                    Date
                                  </th>
                                  <th scope="col" className="relative py-3.5 pl-3 pr-4 sm:pr-6">
                                    <span className="sr-only">View</span>
                                  </th>
                                </tr>
                              </thead>
                              <tbody className="divide-y divide-gray-200 bg-white">
                                {certificates.slice(0, 5).map(certificate => (
                                  <tr key={certificate._id}>
                                    <td className="whitespace-nowrap py-4 pl-4 pr-3 text-sm font-medium text-gray-900 sm:pl-6">
                                      {certificate.program || "未知证书"}
                                    </td>
                                    <td className="whitespace-nowrap px-3 py-4 text-sm text-gray-500">
                                      <span
                                        className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getStatusBadgeClass(certificate.status)}`}
                                      >
                                        {certificate.status.charAt(0).toUpperCase() +
                                          certificate.status.slice(1)}
                                      </span>
                                    </td>
                                    <td className="whitespace-nowrap px-3 py-4 text-sm text-gray-500">
                                      {formatDate(certificate.updatedAt || certificate.createdAt || new Date())}
                                    </td>
                                    <td className="relative whitespace-nowrap py-4 pl-3 pr-4 text-right text-sm font-medium sm:pr-6">
                                      <Link
                                        to={`/dashboard?certificateId=${certificate._id}`}
                                        className="text-blue-600 hover:text-blue-900"
                                      >
                                        View<span className="sr-only">, {certificate.program || "未知证书"}</span>
                                      </Link>
                                    </td>
                                  </tr>
                                ))}
                              </tbody>
                            </table>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </>
            )}

            {activeTab === 'generate-certificate' && (
              <div className="mt-6 px-4 sm:px-0">
                <CertificateGenerator />
              </div>
            )}

            {activeTab === 'certificate-details' && (
              <div className="mt-6 px-4 sm:px-0">
                {certificateLoading ? (
                  <LoadingSpinner message="Loading certificate details..." />
                ) : certificateError ? (
                  <AlertMessage
                    type="error"
                    message={{
                      title: 'Failed to load certificate',
                      details: certificateError,
                    }}
                  />
                ) : selectedCertificate ? (
                  <div className="bg-white shadow overflow-hidden sm:rounded-lg">
                    <div className="px-4 py-5 sm:px-6 flex justify-between items-center">
                      <div>
                        <h3 className="text-lg leading-6 font-medium text-gray-900">
                          Certificate Details
                        </h3>
                        <p className="mt-1 max-w-2xl text-sm text-gray-500">
                          Details and information about your certificate.
                        </p>
                      </div>
                      <button
                        type="button"
                        onClick={() => handleDownloadCertificate(selectedCertificate._id)}
                        className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                        disabled={downloadLoading}
                      >
                        {downloadLoading ? (
                          <>
                            <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                            </svg>
                            下载中...
                          </>
                        ) : (
                          '下载证书'
                        )}
                      </button>
                    </div>
                    <div className="border-t border-gray-200">
                      <dl>
                        <div className="bg-gray-50 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
                          <dt className="text-sm font-medium text-gray-500">证书编号</dt>
                          <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                            {selectedCertificate.certificateNumber || '未分配编号'}
                          </dd>
                        </div>
                        <div className="bg-white px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
                          <dt className="text-sm font-medium text-gray-500">课程/学位</dt>
                          <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                            {selectedCertificate.program || '未指定课程'}
                          </dd>
                        </div>
                        <div className="bg-gray-50 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
                          <dt className="text-sm font-medium text-gray-500">接收者姓名</dt>
                          <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                            {selectedCertificate.recipientName || '未指定接收者'}
                          </dd>
                        </div>
                        <div className="bg-white px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
                          <dt className="text-sm font-medium text-gray-500">发布日期</dt>
                          <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                            {selectedCertificate.issueDate ? formatDate(selectedCertificate.issueDate) : '未指定日期'}
                          </dd>
                        </div>
                        <div className="bg-gray-50 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
                          <dt className="text-sm font-medium text-gray-500">状态</dt>
                          <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                            <span
                              className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getStatusBadgeClass(
                                selectedCertificate.status || 'pending'
                              )}`}
                            >
                              {selectedCertificate.status 
                                ? selectedCertificate.status.charAt(0).toUpperCase() + selectedCertificate.status.slice(1) 
                                : '待处理'}
                            </span>
                          </dd>
                        </div>
                        <div className="bg-white px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
                          <dt className="text-sm font-medium text-gray-500">区块链哈希</dt>
                          <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                            {selectedCertificate.blockchainHash || '尚未生成'}
                          </dd>
                        </div>
                        <div className="bg-gray-50 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
                          <dt className="text-sm font-medium text-gray-500">验证链接</dt>
                          <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                            {selectedCertificate.certificateNumber ? (
                              <a
                                href={`/verify/${selectedCertificate.certificateNumber}`}
                                className="text-blue-600 hover:text-blue-800"
                              >
                                验证此证书
                              </a>
                            ) : (
                              <span className="text-gray-500">证书编号未分配，无法验证</span>
                            )}
                          </dd>
                        </div>
                      </dl>
                    </div>
                  </div>
                ) : (
                  <div className="text-center py-10">
                    <p className="text-gray-500">Certificate not found</p>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'certificates' && (
              <div className="mt-6 px-4 sm:px-0">
                <div className="sm:flex sm:items-center mb-4">
                  <div className="sm:flex-auto">
                    <h3 className="text-lg font-bold leading-6 text-gray-900">
                      {statusFilterState 
                        ? `${statusFilterState.charAt(0).toUpperCase() + statusFilterState.slice(1)} Certificates` 
                        : 'All Certificates'}
                    </h3>
                    <p className="mt-1 text-sm text-gray-500">
                      {statusFilterState 
                        ? `Showing all your ${statusFilterState} certificates` 
                        : 'View and manage all your certificates'}
                    </p>
                  </div>
                  <div className="mt-4 sm:mt-0 sm:ml-16 sm:flex-none">
                    <button
                      type="button"
                      onClick={() => setActiveTab('generate-certificate')}
                      className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                    >
                      Request New Certificate
                    </button>
                  </div>
                </div>
                
                <div className="flex flex-wrap gap-3 mb-4">
                  <button
                    onClick={() => {
                      setStatusFilter(null);
                      setActiveTab('certificates');
                    }}
                    className={`px-3 py-1 text-sm font-medium rounded-md ${!statusFilterState ? 'bg-blue-100 text-blue-800 border border-blue-300' : 'bg-gray-100 text-gray-800 border border-gray-300 hover:bg-gray-200'}`}
                  >
                    All
                  </button>
                  <button
                    onClick={() => {
                      setStatusFilter('pending');
                      setActiveTab('certificates');
                    }}
                    className={`px-3 py-1 text-sm font-medium rounded-md ${statusFilterState === 'pending' ? 'bg-yellow-100 text-yellow-800 border border-yellow-300' : 'bg-gray-100 text-gray-800 border border-gray-300 hover:bg-gray-200'}`}
                  >
                    Pending
                  </button>
                  <button
                    onClick={() => {
                      setStatusFilter('issued');
                      setActiveTab('certificates');
                    }}
                    className={`px-3 py-1 text-sm font-medium rounded-md ${statusFilterState === 'issued' ? 'bg-green-100 text-green-800 border border-green-300' : 'bg-gray-100 text-gray-800 border border-gray-300 hover:bg-gray-200'}`}
                  >
                    Issued
                  </button>
                  <button
                    onClick={() => {
                      setStatusFilter('revoked');
                      setActiveTab('certificates');
                    }}
                    className={`px-3 py-1 text-sm font-medium rounded-md ${statusFilterState === 'revoked' ? 'bg-red-100 text-red-800 border border-red-300' : 'bg-gray-100 text-gray-800 border border-gray-300 hover:bg-gray-200'}`}
                  >
                    Revoked
                  </button>
                </div>
                
                {loading ? (
                  <LoadingSpinner message="Loading certificates..." />
                ) : error ? (
                  <AlertMessage
                    type="error"
                    message={{
                      title: 'Failed to load certificates',
                      details: error,
                    }}
                  />
                ) : (
                  <div className="overflow-hidden shadow ring-1 ring-black ring-opacity-5 md:rounded-lg">
                    {certificates.length === 0 || 
                     (statusFilterState && certificates.filter(cert => cert.status === statusFilterState).length === 0) ? (
                      <div className="bg-white py-12 text-center">
                        <svg
                          className="mx-auto h-12 w-12 text-gray-400"
                          fill="none"
                          viewBox="0 0 24 24"
                          stroke="currentColor"
                          aria-hidden="true"
                        >
                          <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth={1}
                            d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"
                          />
                        </svg>
                        <h3 className="mt-2 text-sm font-medium text-gray-900">
                          {statusFilterState 
                            ? `No ${statusFilterState} certificates found` 
                            : 'No certificates found'}
                        </h3>
                        <p className="mt-1 text-sm text-gray-500">
                          {statusFilterState 
                            ? `You don't have any ${statusFilterState} certificates.` 
                            : 'Get started by requesting your first certificate.'}
                        </p>
                        <div className="mt-6">
                          <button
                            type="button"
                            onClick={() => setActiveTab('generate-certificate')}
                            className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                          >
                            Request Certificate
                          </button>
                        </div>
                      </div>
                    ) : (
                      <table className="min-w-full divide-y divide-gray-300">
                        <thead className="bg-gray-50">
                          <tr>
                            <th
                              scope="col"
                              className="py-3.5 pl-4 pr-3 text-left text-sm font-semibold text-gray-900 sm:pl-6"
                            >
                              Title
                            </th>
                            <th
                              scope="col"
                              className="px-3 py-3.5 text-left text-sm font-semibold text-gray-900"
                            >
                              Status
                            </th>
                            <th
                              scope="col"
                              className="px-3 py-3.5 text-left text-sm font-semibold text-gray-900"
                            >
                              Date
                            </th>
                            <th scope="col" className="relative py-3.5 pl-3 pr-4 sm:pr-6">
                              <span className="sr-only">View</span>
                            </th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200 bg-white">
                          {certificates
                            .filter(cert => !statusFilterState || cert.status === statusFilterState)
                            .map(certificate => (
                            <tr key={certificate._id}>
                              <td className="whitespace-nowrap py-4 pl-4 pr-3 text-sm font-medium text-gray-900 sm:pl-6">
                                {certificate.program || '未知证书'}
                              </td>
                              <td className="whitespace-nowrap px-3 py-4 text-sm text-gray-500">
                                <span
                                  className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getStatusBadgeClass(certificate.status)}`}
                                >
                                  {certificate.status.charAt(0).toUpperCase() +
                                    certificate.status.slice(1)}
                                </span>
                              </td>
                              <td className="whitespace-nowrap px-3 py-4 text-sm text-gray-500">
                                {formatDate(certificate.updatedAt || certificate.createdAt || new Date())}
                              </td>
                              <td className="relative whitespace-nowrap py-4 pl-3 pr-4 text-right text-sm font-medium sm:pr-6">
                                <Link
                                  to={`/dashboard?certificateId=${certificate._id}`}
                                  className="text-blue-600 hover:text-blue-900"
                                >
                                  View<span className="sr-only">, {certificate.program || '未知证书'}</span>
                                </Link>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    )}
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </div>
    </>
  );
};

export default UserDashboard;
